import puppeteer from 'puppeteer';
import fs from 'fs';
import path from 'path';

const BASE_URL = 'https://dotahub.cn';
const OUT = 'scripts/visual-qa/artifacts/round0';
const VIEWPORTS = [
  { name: 'desktop', width: 1440, height: 900 },
  { name: 'mobile', width: 390, height: 844 },
];

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

/** 截图元素完整内容（包括滚动区域外） */
async function screenshotFull(page, el) {
  // 先滚动到元素
  await el.evaluate(e => e.scrollIntoView({ block: 'start' }));
  await sleep(300);
  // 获取完整 bounding rect
  const rect = await el.evaluate(e => {
    const r = e.getBoundingClientRect();
    return { x: r.x, y: r.y, w: r.width, h: r.height };
  });
  // 用 page 截图裁剪
  return await page.screenshot({
    encoding: 'binary',
    clip: { x: Math.max(0, rect.x), y: Math.max(0, rect.y), width: rect.w, height: rect.h },
  });
}

async function captureAll(browser, vp) {
  const page = await browser.newPage();
  await page.setViewport({ width: vp.width, height: vp.height });
  const results = [];

  await page.goto(BASE_URL, { waitUntil: 'networkidle2', timeout: 60000 });
  await sleep(5000);

  // ===== 1. Match Detail =====
  console.log(`  [${vp.name}] Match Detail...`);
  let matchBtnHandle = await page.evaluateHandle(() => {
