async function takeShot(page, el) {
  // 展开元素内所有滚动限制，让内容全高渲染
  await el.evaluate(e => {
    // 遍历元素内所有子元素，移除 height/max-height/overflow 限制
    const walk = (node) => {
      const s = node.style;
      const cls = node.className || '';
      if (cls.includes('overflow') || cls.includes('h-full') || cls.includes('max-h')) {
        s.setProperty('overflow', 'visible', 'important');
        s.setProperty('overflow-y', 'visible', 'important');
        s.setProperty('max-height', 'none', 'important');
        s.setProperty('height', 'auto', 'important');
      }
      for (const child of node.children) walk(child);
    };
    walk(e);
  });
  await sleep(500);

  // 获取展开后的完整 bounding rect
  const rect = await el.evaluate(e => {
    const r = e.getBoundingClientRect();
    return { x: r.x, y: r.y, w: r.width, h: r.height };
  });

  // 用 page screenshot clip 截取完整区域
  return await page.screenshot({
    encoding: 'binary',
    clip: { x: Math.max(0, rect.x), y: Math.max(0, rect.y), width: rect.w, height: rect.h },
  });
}

