import puppeteer from 'puppeteer';
const b = await puppeteer.launch({headless:'new',args:['--no-sandbox']});
const p = await b.newPage();
await p.goto('https://dotahub.cn',{waitUntil:'networkidle2',timeout:30000});
await new Promise(r=>setTimeout(r,3000));
const found = await p.evaluate(()=>!!document.querySelector('[data-visual-role]'));
console.log('data-visual-role present:', found);
if (!found) {
  const slots = await p.evaluate(()=>Array.from(document.querySelectorAll('[data-slot]')).map(e=>e.getAttribute('data-slot')).slice(0,5));
  console.log('data-slot elements:', slots);
}
await b.close();

